public class TrustScoreCalculator {

    public double calculateTrustScore(AIRecommendation recommendation) {
        double trustScore = 0.0;

        // Factor 1: Explainability score (0-25 points)
        trustScore += calculateExplainabilityScore(recommendation);

        // Factor 2: Fairness score (0-25 points)
        trustScore += calculateFairnessScore(recommendation);

        // Factor 3: Transparency score (0-25 points)
        trustScore += calculateTransparencyScore(recommendation);

        // Factor 4: Human control score (0-25 points)
        trustScore += calculateHumanControlScore(recommendation);

        return trustScore;
    }

    private double calculateExplainabilityScore(AIRecommendation rec) {
        // Check if recommendation has human-understandable explanation
        if (rec.hasExplanation() && rec.explanationLength() < MAX_LENGTH) {
            return 25.0;
        }
        return 10.0;
    }

    private double calculateFairnessScore(AIRecommendation rec) {
        // Check for bias across protected attributes
        BiasAnalysis analysis = rec.getBiasAnalysis();
        if (analysis.isFair()) {
            return 25.0;
        }
        return 5.0;
    }

    private double calculateTransparencyScore(AIRecommendation rec) {
        // Check if data sources and limitations are disclosed
        if (rec.isTransparent()) {
            return 25.0;
        }
        return 10.0;
    }

    private double calculateHumanControlScore(AIRecommendation rec) {
        // Check if human can override this recommendation
        if (rec.isHumanOverrideable()) {
            return 25.0;
        }
        return 5.0;
    }

    // Determine if human review is required based on trust score
    public boolean requiresHumanReview(AIRecommendation rec) {
        double score = calculateTrustScore(rec);
        return score < MIN_TRUST_THRESHOLD;
    }
}
